/*
 * atan() test harness -- prints (input_hex, output_hex) pairs.
 *
 * Build two versions:
 *   1. Linked with optimized Andes assembly atan  (test_atan_opt.elf)
 *   2. Linked with toolchain's default atan       (test_atan_ref.elf)
 * Run both, diff the output to find discrepancies.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

#ifdef EN_PERF
#define PF_COUNTER
#include "nds_pfcounter.h"
#endif

static inline uint64_t d2u(double d)
{
    union { double d; uint64_t u; } x;
    x.d = d;
    return x.u;
}

static inline double u2d(uint64_t u)
{
    union { double d; uint64_t u; } x;
    x.u = u;
    return x.d;
}

static volatile double g_acc;

static void emit(double x)
{
#ifdef EN_PERF
    volatile double vx = x;  /* prevent constant-folding of literal arguments */
    g_acc += atan(vx);
#else
    double r = atan(x);
    printf("%016llx %016llx\n", (unsigned long long)d2u(x), (unsigned long long)d2u(r));
#endif
}

static void emit_u(uint64_t bits)
{
    emit(u2d(bits));
}

#ifndef EN_PERF
/* ------------------------------------------------------------------ */
/* Dense sweeps (accuracy path only)                                   */
/* ------------------------------------------------------------------ */

/* Sweep [-100, 100] in 200 steps */
static void test_sweep(void)
{
    int nsteps = 200;
    double step = 200.0 / (double)nsteps;

    for (int i = 0; i <= nsteps; i++)
        emit(-100.0 + (double)i * step);
}

/* Sample [0, 1] every 4503599627370496 ULP (~200 cases) */
static void test_exhaustive_small(void)
{
    uint64_t end = 0x3ff0000000000000ULL; /* 1.0 */
    for (uint64_t b = 0; b <= end; b += 4503599627370496ULL)
        emit_u(b);
}
#endif /* !EN_PERF */

/* ------------------------------------------------------------------ */
/* Representative 100-point test                                        */
/* ------------------------------------------------------------------ */

static void test_representative_100(void)
{
    /* --- Section 1: Special IEEE 754 values (7) --- */
    emit(0.0);
    emit(-0.0);
    emit_u(0x7ff8000000000000ULL);  /* qNaN */
    emit_u(0x7ff0000000000001ULL);  /* sNaN */
    emit_u(0xfff8000000000000ULL);  /* -qNaN */
    emit_u(0x7ff0000000000000ULL);  /* +Inf -> pi/2 */
    emit_u(0xfff0000000000000ULL);  /* -Inf -> -pi/2 */

    /* --- Section 2: Subnormal (denormal) values (6) --- */
    emit_u(0x0000000000000001ULL);  /* min positive subnormal: 2^-1074 */
    emit_u(0x8000000000000001ULL);  /* min negative subnormal */
    emit_u(0x0008000000000000ULL);  /* mid positive subnormal */
    emit_u(0x8008000000000000ULL);  /* mid negative subnormal */
    emit_u(0x000fffffffffffffULL);  /* max positive subnormal: just below DBL_MIN */
    emit_u(0x800fffffffffffffULL);  /* max negative subnormal */

    /* --- Section 3: Normal boundary values (6) --- */
    emit(DBL_MIN);                              /* 2^-1022, smallest normal */
    emit(-DBL_MIN);
    emit_u(0x0010000000000001ULL);  /* one ULP above DBL_MIN */
    emit(DBL_MAX);                              /* largest normal: 0x7fefffffffffffff */
    emit(-DBL_MAX);
    emit_u(0x7fefffffffffffffULL);  /* DBL_MAX itself (bit pattern) */

    /* --- Section 4: Near 1.0 ULP density (8) --- */
    emit_u(0x3fefffffffffffffULL);  /* one ULP below 1.0 */
    emit(1.0);
    emit_u(0x3ff0000000000001ULL);  /* one ULP above 1.0 */
    emit_u(0x3feffffffff00000ULL);  /* a few ULPs below 1.0 */
    emit_u(0x3ff0000000100000ULL);  /* a few ULPs above 1.0 */
    emit(-1.0);
    emit_u(0xbfefffffffffffffULL);  /* one ULP toward zero from -1.0 */
    emit_u(0xbff0000000000001ULL);  /* one ULP away from zero from -1.0 */

    /* --- Section 5: Exponent switching points (6) --- */
    emit_u(0x3fe0000000000000ULL);  /* 0.5 */
    emit_u(0x3fdffffffffffffeULL);  /* one ULP below 0.5 */
    emit_u(0x3fe0000000000001ULL);  /* one ULP above 0.5 */
    emit_u(0x4000000000000000ULL);  /* 2.0 */
    emit_u(0x3fffffffffffffffULL);  /* one ULP below 2.0 */
    emit_u(0x4000000000000001ULL);  /* one ULP above 2.0 */

    /* --- Section 6: Mathematical key values (14) --- */
    /* atan(1/sqrt(3)) = pi/6, atan(1) = pi/4, atan(sqrt(3)) = pi/3 */
    emit(0.5773502691896258);   /* 1/sqrt(3): atan = pi/6 */
    emit(-0.5773502691896258);  /* -1/sqrt(3): atan = -pi/6 */
    emit_u(0x3fe921fb54442d18ULL);  /* pi/4 as input (~0.7853...) */
    emit_u(0xbfe921fb54442d18ULL);  /* -pi/4 as input */
    emit(1.7320508075688772);   /* sqrt(3): atan = pi/3 */
    emit(-1.7320508075688772);  /* -sqrt(3): atan = -pi/3 */
    emit(0.1);
    emit(-0.1);
    emit(0.25);
    emit(-0.25);
    emit(0.75);
    emit(-0.75);
    emit(3.0);
    emit(-3.0);

    /* --- Section 7: Large argument saturation (8) --- */
    /* atan(x) -> pi/2 as x -> +Inf; stress the asymptotic branch */
    emit(10.0);
    emit(-10.0);
    emit(100.0);
    emit(-100.0);
    emit(1.0e10);
    emit(-1.0e10);
    emit(1.0e15);
    emit(-1.0e15);

    /* --- Section 8: ULP neighbors of key atan output boundaries (15) --- */
    /* Inputs that produce outputs near pi/6, pi/4, pi/3, pi/2 */
    /* ULP triplet around x = 1/sqrt(3) (atan output = pi/6) */
    emit_u(0x3fe279a74590331bULL);  /* 1/sqrt(3) - 1 ULP */
    emit_u(0x3fe279a74590331cULL);  /* 1/sqrt(3) exact */
    emit_u(0x3fe279a74590331dULL);  /* 1/sqrt(3) + 1 ULP */
    /* ULP triplet around x = 1.0 (atan output = pi/4) */
    emit_u(0x3fefffffffffffffULL);  /* 1.0 - 1 ULP (already in section 4; kept for triplet) */
    emit_u(0x3ff0000000000000ULL);  /* 1.0 exact */
    emit_u(0x3ff0000000000001ULL);  /* 1.0 + 1 ULP */
    /* ULP triplet around x = sqrt(3) (atan output = pi/3) */
    emit_u(0x3ffbb67ae8584caaULL);  /* sqrt(3) - 1 ULP */
    emit_u(0x3ffbb67ae8584cabULL);  /* sqrt(3) exact */
    emit_u(0x3ffbb67ae8584cacULL);  /* sqrt(3) + 1 ULP */
    /* ULP triplet around x = 1e300 (atan output very close to pi/2) */
    emit_u(0x7e37e43c8800759cULL);  /* 1e300 - 1 ULP */
    emit_u(0x7e37e43c8800759dULL);  /* 1e300 */
    emit_u(0x7e37e43c8800759eULL);  /* 1e300 + 1 ULP */
    /* Negative counterparts */
    emit_u(0xbffbb67ae8584cabULL);  /* -sqrt(3) exact: atan = -pi/3 */
    emit_u(0xbfe279a74590331cULL);  /* -1/sqrt(3) exact: atan = -pi/6 */
    emit(-1.0e300);

    /* --- Section 9: Small-argument fast-path thresholds (8) --- */
    /* atan(x) ~ x for tiny x; implementations often use this below 2^-27 */
    emit_u(0x3fb0000000000000ULL);  /* 2^-12 */
    emit_u(0xbfb0000000000000ULL);  /* -2^-12 */
    emit_u(0x3e50000000000000ULL);  /* 2^-26: near threshold for atan(x)~x */
    emit_u(0xbe50000000000000ULL);  /* -2^-26 */
    emit_u(0x3f80000000000000ULL);  /* 2^-7 */
    emit_u(0xbf80000000000000ULL);  /* -2^-7 */
    emit_u(0x3f20000000000000ULL);  /* 2^-13 */
    emit_u(0xbf20000000000000ULL);  /* -2^-13 */

    /* --- Section 10: Polynomial branch and hard cases (22) --- */
    /* atan polynomial typically has branches at |x|<0.5, 0.5<=|x|<1.5, |x|>=1.5 */
    /* ULP neighbors of branch boundary at |x| = 0.5 */
    emit_u(0x3fdffffffffffffeULL);  /* 0.5 - 2 ULP */
    emit_u(0x3fe0000000000000ULL);  /* 0.5 exact */
    emit_u(0x3fe0000000000002ULL);  /* 0.5 + 2 ULP */
    /* ULP neighbors of branch boundary at |x| = 1.5 */
    emit_u(0x3ff7ffffffffffffULL);  /* 1.5 - 1 ULP */
    emit_u(0x3ff8000000000000ULL);  /* 1.5 exact */
    emit_u(0x3ff8000000000001ULL);  /* 1.5 + 1 ULP */
    emit_u(0xbff8000000000000ULL);  /* -1.5 exact */
    /* Values near pi/2 output (large positive x) */
    emit_u(0x4059000000000000ULL);  /* 100.0 */
    emit_u(0x408f400000000000ULL);  /* 1000.0 */
    emit_u(0x4023fffffffffffffULL); /* just below 10.0 */
    emit_u(0x4024000000000000ULL);  /* 10.0 */
    emit_u(0x4024000000000001ULL);  /* just above 10.0 */
    /* Irrational inputs that exercise full polynomial evaluation */
    emit(M_PI / 4.0);               /* pi/4 ~ 0.7854 */
    emit(-M_PI / 4.0);
    emit(M_PI / 6.0);               /* pi/6 ~ 0.5236 */
    emit(-M_PI / 6.0);
    emit(M_PI / 3.0);               /* pi/3 ~ 1.0472 */
    emit(-M_PI / 3.0);
    /* Values near the integer-exponent boundary (exponent transitions) */
    emit_u(0x4010000000000000ULL);  /* 4.0 */
    emit_u(0x4020000000000000ULL);  /* 8.0 */
    emit_u(0x4030000000000000ULL);  /* 16.0 */
    emit(1.0e200);
}

/* ------------------------------------------------------------------ */

int main(void)
{
#ifdef EN_PERF
    startPFM;
    test_representative_100();
    stopPFM;
    readResult();
    printf("perf acc: %016llx\n", (unsigned long long)d2u((double)g_acc));
#else
    test_representative_100();
    test_sweep();
    test_exhaustive_small();
#endif
    return 0;
}
